1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  previousContracts: number;
4	};
5	
6	export type Item = {
7	  type: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	const FIRST_INSURANCE_RATE = 0.1;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	
33	function itemSurcharge(item: Item): number {
34	  const itemBase = BASE_PREMIUMS[item.type];
35	  let surcharge = 0;
36	  if (item.cursed) surcharge += itemBase * CURSE_SURCHARGE_RATE;
37	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
38	    surcharge += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
39	  }
40	  return surcharge;
41	}
42	
43	function typeSubtotal(type: string, count: number): number {
44	  const isBlock = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
45	  return isBlock ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
46	}
47	
48	function loyaltyDiscount(customer: Customer, policyBase: number): number {
49	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
50	    ? policyBase * LOYALTY_DISCOUNT_RATE
51	    : 0;
52	}
53	
54	export function quote(customer: Customer, items: Item[]): number {
55	  const countsByType: Record<string, number> = {};
56	  for (const item of items) {
57	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
58	  }
59	
60	  const policyBase = Object.entries(countsByType)
61	    .reduce((sum, [type, count]) => sum + typeSubtotal(type, count), 0);
62	
63	  const itemSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
64	  const loyalty = loyaltyDiscount(customer, policyBase);
65	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
66	
67	  return Math.ceil(policyBase + itemSurcharges - loyalty + firstInsurance) + PROCESSING_FEE;
68	}
